#include <bits/stdc++.h>
using namespace std;
int N,M,K;vector<int>L;vector<vector<int>>grid;int brick_count=0;
bool solve(){int fi=-1,fj=-1;for(int i=0;i<N&&fi==-1;i++)for(int j=0;j<M&&fi==-1;j++)if(grid[i][j]==-1){fi=i;fj=j;}if(fi==-1)return true;int id=brick_count++;for(int k=0;k<K;k++){int len=L[k];if(fj+len<=M){bool ok=true;for(int j=fj;j<fj+len;j++)if(grid[fi][j]!=-1){ok=false;break;}if(ok){for(int j=fj;j<fj+len;j++)grid[fi][j]=id;if(solve())return true;for(int j=fj;j<fj+len;j++)grid[fi][j]=-1;}}if(len>1&&fi+len<=N){bool ok=true;for(int i=fi;i<fi+len;i++)if(grid[i][fj]!=-1){ok=false;break;}if(ok){for(int i=fi;i<fi+len;i++)grid[i][fj]=id;if(solve())return true;for(int i=fi;i<fi+len;i++)grid[i][fj]=-1;}}}brick_count--;return false;}
int main(){ios_base::sync_with_stdio(false);cin.tie(NULL);cin>>N>>M>>K;L.resize(K);for(int i=0;i<K;i++)cin>>L[i];grid.assign(N,vector<int>(M,-1));if(!solve()){cout<<"NO\n";return 0;}int total=brick_count;vector<set<int>>adj(total);int dx[]={0,0,1,-1},dy[]={1,-1,0,0};for(int i=0;i<N;i++)for(int j=0;j<M;j++)for(int d=0;d<4;d++){int ni=i+dx[d],nj=j+dy[d];if(ni>=0&&ni<N&&nj>=0&&nj<M&&grid[ni][nj]!=grid[i][j]){adj[grid[i][j]].insert(grid[ni][nj]);}}vector<int>color(total,-1);for(int b=0;b<total;b++){set<int>used;for(int nb:adj[b])if(color[nb]!=-1)used.insert(color[nb]);for(int c=0;c<26;c++)if(!used.count(c)){color[b]=c;break;}}cout<<"YES\n";for(int i=0;i<N;i++){for(int j=0;j<M;j++)cout<<(char)('a'+color[grid[i][j]]);cout<<"\n";}return 0;}
